const EXCHANGE_RATE = 0.92;

async function main() {
  const inputPath = 'transactions.csv';
  const outputPath = 'transactions_eur.csv';

  const content = await readFile(inputPath);
  const { headers, rows } = parseCSV(content);
  const convertedRows = rows.map(row => convertRow(row, headers));
  const outputContent = formatCSV(headers, convertedRows);

  await writeFile(outputPath, outputContent);
}

function parseCSV(text: string): { headers: string[], rows: string[][] } {
  const lines = text.trim().split('\n');
  if (lines.length === 0) return { headers: [], rows: [] };
  const headers = lines[0].split(',').map(h => h.trim());
  const rows = lines.slice(1).map(line => line.split(',').map(cell => cell.trim()));
  return { headers, rows };
}

function formatCSV(headers: string[], rows: string[][]): string {
  return [headers.join(','), ...rows.map(row => row.join(','))].join('\n');
}

function convertRow(row: string[], headers: string[]): string[] {
  const amountIndex = headers.findIndex(h => h.toLowerCase().includes('amount'));
  if (amountIndex === -1) return row;

  const newRow = [...row];
  const amount = parseFloat(newRow[amountIndex]);
  if (!isNaN(amount)) {
    newRow[amountIndex] = (amount * EXCHANGE_RATE).toFixed(2);
  }
  return newRow;
}
