async function main() {
  const logUrl = 'http://server/access-log';
  const reportPath = './reports/daily_report.csv';

  const lines: string[] = [];
  for await (const line of pollSource(logUrl, 1000)) {
    lines.push(line);
  }

  const requests = mapItems(lines, parseLogLine);
  const summary = generateSummary(requests);
  const newRow = formatRow(summary);

  let content = '';
  try {
    content = await readFile(reportPath);
    if (!content.includes('date,total_requests,status_breakdown')) {
      content = 'date,total_requests,status_breakdown\n' + content;
    }
  } catch {
    content = 'date,total_requests,status_breakdown\n';
  }

  await writeFile(reportPath, content + newRow);
}

function parseLogLine(line: string): { method: string; path: string; status: number } {
  const regex = /"(\w+) ([^ ]+) HTTP\/[\d.]+"\s+(\d{3})/;
  const match = line.match(regex);
  if (!match) return { method: 'UNKNOWN', path: 'UNKNOWN', status: 0 };
  return {
    method: match[1],
    path: match[2],
    status: parseInt(match[3], 10)
  };
}

function generateSummary(requests: { method: string; path: string; status: number }[]) {
  const byStatus = groupBy(requests, 'status');
  const total = requests.length;
  const date = new Date().toISOString().split('T')[0];

  return {
    date,
    total_requests: total,
    status_counts: Object.entries(byStatus).map(([status, items]) => ({
      status_code: status,
      count: items.length
    }))
  };
}

function formatRow(summary: any): string {
  const breakdown = summary.status_counts.map(s => `${s.status_code}:${s.count}`).join(',');
  return `${summary.date},${summary.total_requests},${breakdown}`;
}
