async function main(patientId: string) {
  const [labs, medications, vitals] = await Promise.all([
    fetchFromApi(`https://lims.internal/api/patient/${patientId}/results`),
    fetchFromApi(`https://pharmacy.internal/api/patient/${patientId}/medications`),
    queryDatabase(`SELECT * FROM vitals WHERE patient_id = '${patientId}' ORDER BY timestamp DESC LIMIT 5`),
  ]);

  const summary = generatePreVisitSummary(patientId, labs, medications, vitals);
  await writeToDatabase('visit_summaries', { patient_id: patientId, summary, created_at: new Date() });
  await logToAudit({ action: 'generate_pre_visit_summary', patient_id: patientId });
}

function generatePreVisitSummary(patientId: string, labs: any[], medications: any[], vitals: any[]): string {
  const latestVital = vitals[0] || {};
  const activeMeds = medications.filter((m) => m.status === 'active');

  return `
    === PRE-VISIT SUMMARY ===
    Patient ID: ${patientId}
    Labs: ${labs.length} recent results
    Medications: ${activeMeds.length} active prescriptions
    Latest Vitals: BP ${latestVital.bp || 'N/A'}, HR ${latestVital.hr || 'N/A'}, Temp ${latestVital.temp || 'N/A'}
    ========================
  `;
}
