function normalizeMentions(rawData: any[]): Mention[] {
  const [twitter, reddit, hn] = rawData;
  return [
    ...mapItems(twitter, (t) => ({ id: t.id, source: 'twitter', text: t.text })),
    ...mapItems(reddit, (r) => ({ id: r.id, source: 'reddit', text: r.text })),
    ...mapItems(hn, (h) => ({ id: h.id, source: 'hackernews', text: h.text })),
  ];
}

async function analyzeSentiment(mentions: Mention[]): Promise<AnalyzedMention[]> {
  return await Promise.all(
    mapItems(mentions, async (m) => {
      const sentiment = await llmClassify(m.text, ['positive', 'negative', 'neutral']);
      return { ...m, sentiment };
    })
  );
}

function aggregateReport(mentions: AnalyzedMention[]): UnifiedReport {
  const sentimentScore = aggregate(
    mentions,
    (acc, item) => {
      acc[item.sentiment] = (acc[item.sentiment] || 0) + 1;
      acc.total = (acc.total || 0) + 1;
      return acc;
    },
    { positive: 0, negative: 0, neutral: 0, total: 0 }
  );

  const groupedBySource = groupBy(mentions, 'source');
  const attribution = mapItems(
    Object.keys(groupedBySource),
    (source) => ({ source, count: groupedBySource[source].length })
  );

  return { sentiment: sentimentScore, attribution };
}

async function main(brand: string): Promise<UnifiedReport> {
  const rawData = await fetchMentions(brand);
  const normalized = normalizeMentions(rawData);
  const analyzed = await analyzeSentiment(normalized);
  return aggregateReport(analyzed);
}
