interface CartItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
}

interface CartState {
  items: CartItem[];
  lastUpdated: Date;
}

interface CartSummary {
  subtotal: number;
  tax: number;
  shipping: number;
  total: number;
  itemCount: number;
}

const TAX_RATE = 0.08;
const SHIPPING_COST = 5.00;

function calculateSummary(items: CartItem[]): CartSummary {
  const subtotal = aggregate(items, (acc: number, item: CartItem) => acc + (item.price * item.quantity), 0);
  const tax = subtotal * TAX_RATE;
  const shipping = items.length > 0 ? SHIPPING_COST : 0;
  const total = subtotal + tax + shipping;
  const itemCount = aggregate(items, (acc: number, item: CartItem) => acc + item.quantity, 0);

  return {
    subtotal,
    tax,
    shipping,
    total,
    itemCount
  };
}

async function persistCart(state: CartState, summary: CartSummary): Promise<void> {
  await writeToDatabase('shopping_carts', {
    ...state,
    summary
  });
}

async function notifyFrontend(summary: CartSummary): Promise<void> {
  await sendPushNotification(JSON.stringify({
    type: 'CART_UPDATE',
    payload: summary
  }));
}

async function addItemToCart(cart: CartState, item: CartItem): Promise<CartState> {
  const existingItem = cart.items.find(i => i.id === item.id);
  if (existingItem) {
    return {
      ...cart,
      items: mapItems(cart.items, i => i.id === item.id ? { ...i, quantity: i.quantity + item.quantity } : i),
      lastUpdated: new Date()
    };
  }
  return {
    ...cart,
    items: [...cart.items, item],
    lastUpdated: new Date()
  };
}

async function removeItemFromCart(cart: CartState, itemId: string): Promise<CartState> {
  const newItems = filterBy(cart.items, i => i.id !== itemId);
  return {
    ...cart,
    items: newItems,
    lastUpdated: new Date()
  };
}

async function handleCartEvent(event: { type: 'ADD' | 'REMOVE', payload: any }, cart: CartState): Promise<CartSummary> {
  let newState: CartState;

  if (event.type === 'ADD') {
    newState = await addItemToCart(cart, event.payload);
  } else if (event.type === 'REMOVE') {
    newState = await removeItemFromCart(cart, event.payload);
  } else {
    throw new Error('Unknown event type');
  }

  const summary = calculateSummary(newState.items);

  await Promise.all([
    persistCart(newState, summary),
    notifyFrontend(summary)
  ]);

  return summary;
}

async function main() {
  const initialCart: CartState = {
    items: [],
    lastUpdated: new Date()
  };

  const addItemEvent = { type: 'ADD' as const, payload: { id: '1', name: 'Widget', price: 10, quantity: 1 } };
  const summary = await handleCartEvent(addItemEvent, initialCart);
  console.log('Cart Updated:', summary);
}
