function setCachedPrice(key: string, price: number): void {
  priceCache.set(key, { price, timestamp: Date.now() });
}

async function fetchPriceWithRetry(productId: string): Promise<number> {
  const url = `https://api.pricing.com/v1/${productId}`;
  const maxRetries = 3;
  let lastError: Error | null = null;

  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    await logToAudit({
      action: 'fetch_price_attempt',
      productId,
      attempt: attempt + 1,
      maxRetries,
      timestamp: new Date().toISOString()
    });

    try {
      const response = await fetchFromApi(url);
      if (response && response.price !== undefined) {
        setCachedPrice(productId, response.price);
        return response.price;
      }
      throw new Error('Invalid response structure');
    } catch (error) {
      lastError = error as Error;
      if (attempt < maxRetries) {
        const backoffMs = Math.pow(2, attempt) * 1000;
        await sleep(backoffMs);
      }
    }
  }

  const cachedPrice = getCachedPrice(productId);
  if (cachedPrice !== null) {
    await logToAudit({
      action: 'fetch_price_fallback',
      productId,
      source: 'cache',
      price: cachedPrice
    });
    return cachedPrice;
  }

  throw lastError || new Error('Failed to fetch price and no cache available');
}
